import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by sanitizing and encoding it
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String sanitizedInput = codec.encodeForHTML(userInput);
        String output = "<p>Welcome, " + sanitizedInput + "</p>";

        try {
            PrintWriter out = new PrintWriter(new FileWriter("output.html"));
            out.println(output);
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
